const item = $input.first();

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');

if (!buffer) {
  throw new Error('Keine Binärdaten im Feld data gefunden.');
}

const file = item.binary.data;
const base64 = buffer.toString('base64');

const prompt = [
  'Du bist ein Rechnungsparser für ein Automatenlager. Extrahiere aus der Rechnung ausschließlich valides JSON. Keine Markdown-Codeblöcke, keine Erklärung.',
  '',
  'Schema:',
  '{"invoice_id":"","supplier":"","purchase_date":"YYYY-MM-DD","invoice_lines":[{"source_item":"","quantity":0,"pack_size":1,"mhd":"YYYY-MM-DD oder leer","unit_cost":0,"mwst_satz":0,"nayax_product_name":"","mdb_code":"","sale_price_eur":""}]}',
  '',
  'Regeln:',
  'purchase_date ist das Rechnungsdatum oder Lieferdatum, wenn kein Rechnungsdatum erkennbar ist.',
  '',
  'quantity ist die Anzahl der gekauften verkaufbaren Einheiten bzw. Verkaufspackungen, nicht die Anzahl einzelner Stücke innerhalb einer Packung.',
  '',
  'Wenn eine Positionsbezeichnung mehrere Zahlen mit "x" enthält, dann ist die erste Zahl vor dem ersten "x" die quantity.',
  '',
  'Beispiele:',
  '"30x2x21,5g KINDER BU KLASSIK" bedeutet quantity = 30, weil 30 Doppelpackungen gekauft wurden.',
  '"24x36g M&M CRISPY EINZELBEUTEL" bedeutet quantity = 24.',
  '"12x0,5L GETRÄNK" bedeutet quantity = 12.',
  '',
  'pack_size ist die Anzahl einzelner Stuecke innerhalb einer Verkaufspackung. Default 1.',
  '',
  'Beispiele:',
  '"30x2x21,5g KINDER BU KLASSIK" bedeutet quantity = 30 und pack_size = 2 (jede Doppelpackung enthaelt 2 Riegel).',
  '"4x4x40g SNICKERS" bedeutet quantity = 4 und pack_size = 4 (4 Vierer-Packs, je 4 Riegel).',
  '"24x36g M&M CRISPY EINZELBEUTEL" bedeutet quantity = 24 und pack_size = 1.',
  '"12x0,5L GETRAENK" bedeutet quantity = 12 und pack_size = 1.',
  '',
  'unit_cost ist der Netto- oder Brutto-Einzelpreis pro Verkaufspackung (nicht pro Einzelstueck), wenn eindeutig erkennbar, sonst leer.',
  '',
  'mwst_satz ist der Mehrwertsteuersatz fuer diese Position in Prozent, 7 oder 19. Aus der Rechnung extrahieren wenn klar ersichtlich (z.B. Steuersatz-Spalte, "7%", "MwSt 7%"). Wenn nicht eindeutig erkennbar, 0 setzen.',
  '',
  'MHD nur übernehmen, wenn es auf der Rechnung steht.',
  '',
  'nayax_product_name zunächst aus source_item ableiten.',
  '',
  'mdb_code und sale_price_eur leer lassen, wenn nicht auf der Rechnung vorhanden.',
  '',
  'Wenn eine Position unklar ist, trotzdem aufnehmen und fehlende Werte leer lassen.'
].join('\n');

const requestBody = {
  model: 'claude-sonnet-4-6',
  max_tokens: 4000,
  messages: [
    {
      role: 'user',
      content: [
        {
          type: 'document',
          source: {
            type: 'base64',
            media_type: 'application/pdf',
            data: base64
          }
        },
        {
          type: 'text',
          text: prompt
        }
      ]
    }
  ]
};

return [
  {
    json: {
      claude_request_body: JSON.stringify(requestBody),
      mime_type: file.mimeType || 'application/pdf',
      file_name: file.fileName || 'rechnung.pdf',
      drive_file_id: item.json.id,
      drive_file_name: item.json.name
    }
  }
];

const raw = $json.content?.[0]?.text;

if (!raw) {
  throw new Error('Claude Antwort enthält keinen Text.');
}

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error('Claude hat kein valides JSON geliefert: ' + raw.slice(0, 300));
}

return [
  {
    json: {
      ...parsed,
      drive_file_id: $('Code - Claude Input vorbereiten').first().json.drive_file_id,
      drive_file_name: $('Code - Claude Input vorbereiten').first().json.drive_file_name
    }
  }
];

const invoice = $items('Code - Claude JSON parsen')[0].json;
const products = $items('Google Sheets - Produkte lesen').map(i => i.json);
const batches = $items('Google Sheets - Lagerchargen lesen').map(i => i.json);
const aliases = $items('Google Sheets - Produkt_Aliase lesen').map(i => i.json);

const now = new Date().toISOString();

function clean(v) {
  return String(v ?? '').replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
}

function normalize(v) {
  return clean(v)
    .toLowerCase()
    .replace(/&/g, 'und')
    .replace(/\+/g, 'plus')
    .replace(/ä/g, 'ae')
    .replace(/ö/g, 'oe')
    .replace(/ü/g, 'ue')
    .replace(/ß/g, 'ss')
    .replace(/[^a-z0-9]/g, '');
}

function keyFromName(name) {
  const base = clean(name)
    .toUpperCase()
    .replace(/Ä/g, 'AE')
    .replace(/Ö/g, 'OE')
    .replace(/Ü/g, 'UE')
    .replace(/ẞ/g, 'SS')
    .replace(/ß/g, 'SS')
    .replace(/&/g, 'UND')
    .replace(/\+/g, 'PLUS')
    .replace(/[^A-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
  return `SKU_${base || 'UNBEKANNT'}`;
}

function batchId(productKey, purchaseDate, existingCount) {
  const ymd = clean(purchaseDate).replace(/-/g, '') || new Date().toISOString().slice(0,10).replace(/-/g, '');
  return `B_${String(productKey).replace(/^SKU_/, '')}_${ymd}_${existingCount + 1}`;
}

function nameMatches(a, b) {
  const aa = normalize(a);
  const bb = normalize(b);
  if (!aa || !bb) return false;
  if (aa === bb) return true;
  if (aa.length >= 8 && bb.includes(aa)) return true;
  if (bb.length >= 8 && aa.includes(bb)) return true;
  return false;
}

function findProduct(line) {
  const source = line.source_item;
  const nayax = line.nayax_product_name;

  const alias = aliases.find(a =>
    nameMatches(a.alias_name, source) ||
    nameMatches(a.alias_name, nayax) ||
    nameMatches(a.source_item, source)
  );

  if (alias && clean(alias.product_key)) {
    const product = products.find(p => clean(p.product_key) === clean(alias.product_key));
    if (product) return { product, confidence: 'hoch', reason: 'Alias gefunden' };
  }

  const byName = products.find(p =>
    nameMatches(p.nayax_product_name || p.internal_product_name, nayax) ||
    nameMatches(p.internal_product_name || p.nayax_product_name, source)
  );

  if (byName) {
    return { product: byName, confidence: 'mittel', reason: 'Namensähnlichkeit gefunden' };
  }

  return { product: null, confidence: 'prüfen', reason: 'Kein Produkt gefunden' };
}

const suggestions = [];
const lines = invoice.invoice_lines || [];

for (const [index, line] of lines.entries()) {
  const match = findProduct(line);
  const isKnown = !!match.product;
  const productKey = isKnown ? clean(match.product.product_key) : keyFromName(line.nayax_product_name || line.source_item);
  const existingBatchCount = batches.filter(b => clean(b.product_key) === productKey).length;

  const missing = [];
  if (!clean(invoice.invoice_id)) missing.push('invoice_id');
  if (!clean(invoice.supplier)) missing.push('supplier');
  if (!clean(invoice.purchase_date)) missing.push('purchase_date');
  if (!clean(line.source_item)) missing.push('source_item');
  if (!Number.isFinite(Number(line.quantity)) || Number(line.quantity) <= 0) missing.push('quantity');
  if (!clean(line.nayax_product_name)) missing.push('nayax_product_name');

  const changeType = isKnown ? 'EXISTING_PRODUCT_NEW_BATCH' : 'NEW_PRODUCT_AND_BATCH';

  suggestions.push({
    created_at: now,
    source_file_id: invoice.drive_file_id,
    source_file_name: invoice.drive_file_name,
    invoice_id: clean(invoice.invoice_id),
    supplier: clean(invoice.supplier),
    purchase_date: clean(invoice.purchase_date),
    line_number: index + 1,
    source_item: clean(line.source_item),
    detected_quantity: Number(line.quantity ?? 0),
    detected_pack_size: Number(line.pack_size ?? 1) || 1,
    detected_mwst_satz: Number(line.mwst_satz ?? 0) || 0,
    detected_mhd: clean(line.mhd),
    detected_unit_cost: line.unit_cost ?? '',
    mdb_code: clean(line.mdb_code),
    approval_id: `APP_${invoice.drive_file_id}_${index + 1}`,
    nayax_product_name: clean(line.nayax_product_name || line.source_item),
    existing_product_key: isKnown ? productKey : '',
    existing_product_name: isKnown ? (match.product.internal_product_name || match.product.nayax_product_name || '') : '',
    suggested_product_key: productKey,
    suggested_batch_id: batchId(productKey, invoice.purchase_date, existingBatchCount),
    suggested_storage_location: $('Config - WF2').first().json.default_storage_location || 'Lager',
    suggested_action: changeType,
    confidence: missing.length ? 'unvollständig' : match.confidence,
    needs_user_input: missing.length ? 'TRUE' : 'FALSE',
    missing_fields: missing.join(', '),
    approved: 'FALSE',
    processed: 'FALSE',
    notes: match.reason
  });
}

if (!suggestions.length) {
  throw new Error('Keine Rechnungspositionen erkannt. Datei wird nicht verschoben.');
}

return suggestions.map(s => ({ json: s }));

const files = $json.files || [];

if (!files.length) {
  throw new Error('Keine PDF-Rechnung im Rechnungseingang gefunden.');
}

// Nimm die erste Datei
return [
  {
    json: files[0]
  }
];

const rows = $input.all().map(i => i.json);
const approvalIds = rows.map(r => String(r.approval_id || '').trim()).filter(Boolean);
if (!approvalIds.length) return [];
return [{ json: {
  source: 'WF1_Rechnungseingang',
  detected_reason: 'INVOICE_PROPOSALS_CREATED',
  approval_ids: [...new Set(approvalIds)].join(','),
  proposals_created: approvalIds.length,
  first_approval_id: approvalIds[0]
} }];

